import{_ as t,c as o,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Release Notes: Version Evolution | Antigravity-Manager","description":"Learn how to track Antigravity Tools version evolution and release notes. Confirm current version in Settings About page, check updates, and verify upgrade impact with /healthz.","frontmatter":{"title":"Release Notes: Version Evolution | Antigravity-Manager","sidebarTitle":"Release Notes","subtitle":"Release Notes: Version Evolution","description":"Learn how to track Antigravity Tools version evolution and release notes. Confirm current version in Settings About page, check updates, and verify upgrade impact with /healthz.","tags":["changelog","release","upgrade","troubleshooting"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}'),n={name:"lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function i(s,e,l,d,u,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="version-evolution-follow-readme-embedded-changelog" tabindex="-1">Version Evolution: Follow README Embedded Changelog <a class="header-anchor" href="#version-evolution-follow-readme-embedded-changelog" aria-label="Permalink to &quot;Version Evolution: Follow README Embedded Changelog&quot;">​</a></h1><p>When you&#39;re preparing to upgrade Antigravity Tools, the worst fear isn&#39;t &quot;not updating to the latest version&quot; — it&#39;s &quot;updating only to discover breaking compatibility changes.&quot; This page explains <strong>how to read the Antigravity Tools Changelog (version evolution)</strong> so you can determine: what will this update affect for you?</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Quickly confirm current version, check updates, and get download entry in Settings → About page</li><li>Read only version sections relevant to you in the README Changelog (instead of scrolling from start to finish)</li><li>Before upgrading: confirm if there are &quot;manual configuration/model mapping change&quot; reminders</li><li>After upgrading: run minimum verification (<code>/healthz</code>) to confirm proxy still works</li></ul><h2 id="what-is-a-changelog" tabindex="-1">What is a Changelog? <a class="header-anchor" href="#what-is-a-changelog" aria-label="Permalink to &quot;What is a Changelog?&quot;">​</a></h2><p><strong>Changelog</strong> is a list that records &quot;what changed in this release&quot; organized by version. Antigravity Tools writes it directly in the README under &quot;版本演进&quot; (Version Evolution), with each version labeled with date and key changes. Reviewing the Changelog before upgrading reduces the chance of hitting compatibility changes or regression issues.</p><h2 id="when-to-use-this-page" tabindex="-1">When to Use This Page <a class="header-anchor" href="#when-to-use-this-page" aria-label="Permalink to &quot;When to Use This Page&quot;">​</a></h2><ul><li>You&#39;re upgrading from an old version to a new version and want to confirm risk points first</li><li>You&#39;re encountering an issue (like 429/0 Token/Cloudflared) and want to verify if it was fixed in recent versions</li><li>You&#39;re maintaining a unified version in your team and need a method for colleagues to read changes by version</li></ul><h2 id="🎒-preparation" tabindex="-1">🎒 Preparation <a class="header-anchor" href="#🎒-preparation" aria-label="Permalink to &quot;🎒 Preparation&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prepare Your Upgrade Path First</p><p>There are many installation/upgrade methods (brew, manual download from Releases, in-app update). If you haven&#39;t decided which path to use, first review <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/start/installation/">Installation &amp; Upgrades: Best Desktop Installation Paths (brew / releases)</a></strong>.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-confirm-your-current-version-in-about-page" tabindex="-1">Step 1: Confirm Your Current Version in About Page <a class="header-anchor" href="#step-1-confirm-your-current-version-in-about-page" aria-label="Permalink to &quot;Step 1: Confirm Your Current Version in About Page&quot;">​</a></h3><p><strong>Why</strong> The Changelog is organized by version. You need to know your current version first, so you know &quot;where to start reading.&quot;</p><p>Navigation: <strong>Settings</strong> → <strong>About</strong>.</p><p><strong>What you should see</strong>: The page title area displays the app name and version number (e.g., <code>v3.3.49</code>).</p><h3 id="step-2-click-check-updates-to-get-latest-version-and-download-entry" tabindex="-1">Step 2: Click &quot;Check Updates&quot; to Get Latest Version and Download Entry <a class="header-anchor" href="#step-2-click-check-updates-to-get-latest-version-and-download-entry" aria-label="Permalink to &quot;Step 2: Click &quot;Check Updates&quot; to Get Latest Version and Download Entry&quot;">​</a></h3><p><strong>Why</strong> You need to know &quot;what&#39;s the latest version number&quot; first, so you can pick out the version sections you&#39;ve crossed in the Changelog.</p><p>Click &quot;检查更新&quot; (Check Updates) in the About page.</p><p><strong>What you should see</strong>:</p><ul><li>If an update is available: Prompt &quot;new version available&quot; with a download button (opens <code>download_url</code>)</li><li>If already latest: Prompt &quot;latest version&quot;</li></ul><h3 id="step-3-go-to-readme-changelog-and-only-read-versions-you-ve-crossed" tabindex="-1">Step 3: Go to README Changelog and Only Read Versions You&#39;ve Crossed <a class="header-anchor" href="#step-3-go-to-readme-changelog-and-only-read-versions-you-ve-crossed" aria-label="Permalink to &quot;Step 3: Go to README Changelog and Only Read Versions You&#39;ve Crossed&quot;">​</a></h3><p><strong>Why</strong> You only need to care about changes &quot;from your current version to the latest version&quot; — you can skip other historical versions.</p><p>Open the README, locate <strong>&quot;版本演进&quot;</strong> (Version Evolution), and read from the latest version downward until you see your current version.</p><p><strong>What you should see</strong>: Versions are listed in <code>vX.Y.Z (YYYY-MM-DD)</code> format, with each version having grouped explanations (e.g., core fixes / feature enhancements).</p><h3 id="step-4-perform-minimum-verification-after-upgrading" tabindex="-1">Step 4: Perform Minimum Verification After Upgrading <a class="header-anchor" href="#step-4-perform-minimum-verification-after-upgrading" aria-label="Permalink to &quot;Step 4: Perform Minimum Verification After Upgrading&quot;">​</a></h3><p><strong>Why</strong> The first thing after upgrading isn&#39;t &quot;running complex scenarios&quot; — it&#39;s confirming the proxy can still start normally and be probed by clients.</p><p>Follow the <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Launch Local Reverse Proxy and Connect First Client (/healthz + SDK Configuration)</a></strong> flow, and at least verify <code>GET /healthz</code> once.</p><p><strong>What you should see</strong>: <code>/healthz</code> returns success (used to confirm service availability).</p><h2 id="recent-version-summary-excerpt-from-readme" tabindex="-1">Recent Version Summary (Excerpt from README) <a class="header-anchor" href="#recent-version-summary-excerpt-from-readme" aria-label="Permalink to &quot;Recent Version Summary (Excerpt from README)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Points You Should Focus On</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>Thinking interruption and 0 Token defense; remove <code>gemini-2.5-flash-lite</code> and remind you to manually replace custom mappings; language/theme settings take effect immediately; monitoring dashboard enhancements; OAuth compatibility improvements</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Windows platform background process silent running (fix console flicker)</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>Image generation parameter mapping enhancements (<code>size</code>/<code>quality</code>); Cloudflared tunnel support; fix startup failure caused by merge conflicts; three-tier progressive context compression</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">How to Quickly Judge &quot;Will This Update Affect Me&quot;</p><p>Prioritize finding these two types of sentences:</p><ul><li><strong>User reminders / You need to modify</strong>: For example, explicitly naming a default model being removed, requiring you to manually adjust custom mappings</li><li><strong>Core fixes / Compatibility fixes</strong>: For example, 0 Token, 429, Windows flicker, startup failure — these &quot;will break your usage&quot; issues</li></ul></div><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Content</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>README embedded Changelog (Version Evolution)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L324-L455" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>324-455</td></tr><tr><td>About page display version number and &quot;Check Updates&quot; button</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L821-L954" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>821-954</td></tr><tr><td>About page &quot;Check Updates&quot; command return structure</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L187-L215" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>187-215</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Current version number (build metadata)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/package.json#L1-L4" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-4</td></tr></tbody></table></details>',34)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
